    // Set to track canonical pairs processed: store the lexicographically smaller character of the pair.
    std::set<char> processed_pairs;

    // 2. Iterate over unique characters present in s
    for (auto const& [c, freq_c] : frequencies) {
        char m = get_mirror(c);

        // Determine the canonical representative of the pair (c, m)
        char canonical_rep = std::min(c, m);

